import React from "react"
import Header from "./Header"
import arrow from "../assets/images/arrow-down.png"
import { Button } from "carbon-components-react"

export default function HomeMain({ onScroll }) {
  return (
    <div className="home-main">
      <div className="home-main-background" />
      <div className="home-main-content">
        <Header />

        <div className="flex-center home-title-container">
          <h2>Learn from role models</h2>
          <p>
            Learn from role model’s priceless experience
            <br /> and practical lessons of their lifetime, exclusively for you.
          </p>
        </div>

        <div className="bx--grid home-box">
          <div className="bx--row">
            <div className="bx--col bx--col-sm-4">
              10-min video
              <br />
              at a time
            </div>
            <div className="bx--col bx--col-sm-4">
              Cinematic
              <br />
              learning experience
            </div>
            <div className="bx--col bx--col-sm-4">
              Your language,
              <br />
              anywhere, anytime
            </div>
          </div>
        </div>

        <div className="arrow-down flex-center">
          <Button kind="ghost" onClick={onScroll}>
            <img src={arrow} alt="go-down" />
          </Button>
        </div>
      </div>
    </div>
  )
}
