import "carbon-components/css/carbon-components.min.css"
import "./video-js.css"
import "./App.css"
import Routes from "./Routes"
import { SWRConfig } from "swr"
import { fetcherBasicAuth, fetcherWithToken } from "./Api"
import { TokenProvider } from "./Hooks"

function fetcher(param) {
  if (param.includes("access_token")) {
    return fetcherWithToken(param)
  }

  return fetcherBasicAuth(param)
}

function App() {
  return (
    <div className="App">
      <TokenProvider>
        <SWRConfig
          value={{
            fetcher,
            revalidateOnFocus: false
          }}
        >
          <Routes />
        </SWRConfig>
      </TokenProvider>
    </div>
  )
}

export default App
