import useSWR from "swr"
import { useToken } from "./useToken"

export function useLessons(collectionId) {
  const { token } = useToken()
  const { data: lessons } = useSWR(
    () =>
      collectionId &&
      (token
        ? `content_relations?offset=0&limit=100&type=All&parent_content_id=Collection_${collectionId}&sort=asc&access_token=${token}`
        : `content_relations?offset=0&limit=100&type=All&parent_content_id=Collection_${collectionId}&sort=asc`)
  )

  let groupedLessons = []
  let index = -1
  lessons?.data?.forEach((item) => {
    if (item.Title) {
      groupedLessons.push({ ...item, extras: [] })
      index++
    } else {
      groupedLessons[index].extras = [...groupedLessons[index].extras, item]
    }
  })

  return groupedLessons
}
