import useSWR from "swr"
import { useToken } from "./useToken"

export function usePrice(collectionId) {
  const { token } = useToken()
  const { data: price } = useSWR(
    () =>
      collectionId &&
      (token
        ? `plans/contents/${collectionId}?Platform=web&CompanyID=888888888888888888888&access_token=${token}`
        : `plans/contents/${collectionId}?Platform=web&CompanyID=888888888888888888888`)
  )
  return price?.data?.[0]
}
