import React from "react"
import { Link } from "react-router-dom"
import { usePurchased } from "../Hooks/usePurchased"

export default function Purchased() {
  const purchased = usePurchased()
  return (
    <div className="purchased">
      <h2>Purchased</h2>
      <div className="purchased-courses">
        {purchased?.map((item, index) => (
          <Link to={`/course/${item.ContentID?.Slug}`} key={index}>
            <div className="purchased-course">
              <img
                src={item.ContentID?.ContentThumbnailPath?.[0]?.URL}
                alt={item.ContentID?.Slug}
              />
              <p>{`Available until `}</p>
            </div>
          </Link>
        ))}
      </div>
    </div>
  )
}
