import React, { useState } from "react"
import play from "../assets/images/play.png"
import { Link } from "react-router-dom"
import ExtraPlayer from "./ExtraPlayer"
import { useCollections, useLessons } from "../Hooks"

export default function CourseCollection() {
  const [open, setOpen] = useState()
  const collections = useCollections("selojene")
  const lessons = useLessons(collections?.CollectionID)

  const handleOpenModal = () => {
    setOpen(true)
  }

  const handleCloseModal = () => {
    setOpen(false)
  }

  return (
    <div className="course-collection">
      <ExtraPlayer open={open} onClose={handleCloseModal} />
      {lessons?.map((item, index) => (
        <div key={item.ContentID} className="collection-container">
          <h4>{`Lesson ${index + 1}`}</h4>
          <div className="lesson-container">
            <Link to="/lesson">
              <div className="lesson-thumbnail">
                <img src={item.ContentThumbnailPath} alt={item.name} />
                <div className="play-icon-container flex-center">
                  <img src={play} alt="play" />
                </div>
              </div>
            </Link>
            <div className="lesson-desc">
              <h4>{item.Title}</h4>
              <p>{item.Caption}</p>
              <p className="lesson-duration">{item.Duration}:00</p>
            </div>
          </div>

          {!!item.extras?.length && (
            <div className="extras-container">
              <h4>Extras</h4>

              {item.extras?.map((extra) => (
                <div key={extra.ContentID} className="extra-container">
                  <div className="extra-thumbnail" onClick={handleOpenModal}>
                    <img src={extra.ContentThumbnailPath} alt={item.name} />
                  </div>
                  <div>
                    <p>{extra.Caption}</p>
                    {extra.ContainerType?.includes("ar") && (
                      <p className="extra-note">Mobile app only</p>
                    )}
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      ))}
    </div>
  )
}
