import React, { useRef } from "react"
import HomeMain from "../Components/HomeMain"
import Footer from "../Components/Footer"
import Faq from "../Components/Faq"
import HomePlayers from "../Components/HomePlayers"

export default function Home() {
  const homePlayerRef = useRef()
  const handleScroll = () => {
    homePlayerRef.current.focus()
    homePlayerRef.current.scrollIntoView({ behavior: "smooth", block: "start" })
  }

  return (
    <div>
      <HomeMain onScroll={handleScroll} />
      <HomePlayers divRef={homePlayerRef} />
      <Faq />
      <Footer />
    </div>
  )
}
