import React, { useState, useEffect, useRef } from "react"
import {
  Modal,
  Button,
  Loading,
  InlineNotification
} from "carbon-components-react"
import { useLogin, useRegister, useToken } from "../Hooks"
import { Link } from "react-router-dom"

export default function SignIn() {
  const [openSignin, setOpenSignin] = useState(false)
  const [openSignup, setOpenSignup] = useState(false)
  const [isLoading, setIsLoading] = useState(false)
  const [loginData, setLoginData] = useState({})
  const [registerData, setRegisterData] = useState({})

  const timerRef = useRef()
  const { onLogin, status: statusLogin } = useLogin()
  const { onRegister, status: statusRegister } = useRegister()
  const { token } = useToken()

  const handleOpenSigninModal = () => {
    setOpenSignin(true)
    setIsLoading(true)
  }

  const handleCloseSigninModal = () => {
    setOpenSignin(false)
  }

  const handleSwitchToSignupModal = () => {
    setOpenSignin(false)
    setOpenSignup(true)
    setIsLoading(true)
  }

  const handleSwitchToSigninModal = () => {
    setOpenSignup(false)
    setOpenSignin(true)
    setIsLoading(true)
  }

  const handleCloseSignupModal = () => {
    setOpenSignup(false)
  }

  const handleSignIn = (e) => {
    e.preventDefault()
    onLogin({ ...loginData, onSucess: handleCloseSigninModal })
  }

  const handleSignUp = (e) => {
    e.preventDefault()
    onRegister({ ...registerData, onSucess: handleCloseSignupModal })
  }

  const handleChangeLoginData = (e) => {
    setLoginData((data) => ({ ...data, [e.target.name]: e.target.value }))
  }

  const handleChangeRegisterData = (e) => {
    setRegisterData((data) => ({ ...data, [e.target.name]: e.target.value }))
  }

  useEffect(() => {
    if (isLoading && !timerRef.current)
      timerRef.current = setTimeout(() => {
        setIsLoading(false)
        timerRef.current = null
      }, 1000)
  }, [isLoading])

  return (
    <div className="signin">
      <Modal
        open={openSignin}
        modalHeading=""
        passiveModal
        size="sm"
        hasForm={false}
        onRequestClose={handleCloseSigninModal}
      >
        <div className="signin-modal account-form">
          {isLoading ? (
            <div className="loading-spiner">
              <Loading
                description="Active loading indicator"
                withOverlay={false}
              />
              <p>Please wait</p>
            </div>
          ) : (
            <>
              <h4>Sign In</h4>
              {statusLogin?.isLogin === false && (
                <InlineNotification
                  kind="error"
                  title={statusLogin?.message}
                  hideCloseButton
                />
              )}
              <form onSubmit={handleSignIn}>
                <input
                  placeholder="Email"
                  name="username"
                  onChange={handleChangeLoginData}
                />
                <input
                  placeholder="Password"
                  name="password"
                  onChange={handleChangeLoginData}
                />
                <Button className="submit" type="submit">
                  Sign In
                </Button>
                <div className="to-signup">
                  Not registered?
                  <Button kind="ghost" onClick={handleSwitchToSignupModal}>
                    Sign up now
                  </Button>
                </div>
              </form>
            </>
          )}
        </div>
      </Modal>

      <Modal
        open={openSignup}
        modalHeading=""
        passiveModal
        size="sm"
        hasForm={false}
        onRequestClose={handleCloseSignupModal}
      >
        <div className="signup-modal account-form">
          {isLoading ? (
            <div className="loading-spiner">
              <Loading
                description="Active loading indicator"
                withOverlay={false}
              />
              <p>Please wait</p>
            </div>
          ) : (
            <>
              <h4>Sign Up</h4>
              {statusRegister?.isRegister === false && (
                <InlineNotification
                  kind="error"
                  title={statusRegister?.message}
                  hideCloseButton
                />
              )}
              <form onSubmit={handleSignUp}>
                <input
                  placeholder="Email"
                  name="email"
                  onChange={handleChangeRegisterData}
                />
                <input
                  placeholder="Password"
                  type="password"
                  name="password"
                  onChange={handleChangeRegisterData}
                />
                <input
                  placeholder="Confirm password"
                  type="password"
                  name="passwordConfirmation"
                  onChange={handleChangeRegisterData}
                />
                <div className="to-signin">
                  Already registered?
                  <Button kind="ghost" onClick={handleSwitchToSigninModal}>
                    Sign in
                  </Button>
                </div>
                <Button className="submit" type="submit">
                  Sign Up
                </Button>
              </form>
            </>
          )}
        </div>
      </Modal>
      {token ? (
        <Link to="/account" className="signin-header">
          Account
        </Link>
      ) : (
        <Button
          className="signin-header"
          kind="ghost"
          onClick={handleOpenSigninModal}
        >
          Sign in
        </Button>
      )}
    </div>
  )
}
