import React, { useState, useRef } from "react"
import VideoPlayer from "./VideoPlayer"
import mute from "../assets/images/mute.png"
import unmute from "../assets/images/unmute.png"
import maximize from "../assets/images/maximize.png"
import { Button } from "carbon-components-react"
import BuyAccess from "./BuyAccess"
import { useCollections, usePrice } from "../Hooks"

const IconUnmute = () => <img src={unmute} alt="unmute" />
const IconMute = () => <img src={mute} alt="mute" />
const IconMaximize = () => <img src={maximize} alt="maimize" />

export default function CoursePlayer() {
  const [isMuted, setIsMuted] = useState(true)
  const [isFullWindow, setIsFullWindow] = useState(false)
  const playerRef = useRef()
  const collections = useCollections("selojene")
  const price = usePrice(collections?.CollectionID)

  const handleFullScreen = () => {
    document.activeElement.blur()
    playerRef.current.enterFullScreen()
    setIsFullWindow(true)
  }

  const handleExitFullWindow = () => {
    setIsFullWindow(false)
  }

  const handleToogleMuted = () => {
    setIsMuted((muted) => !muted)
    playerRef.current.toogleMuted(!isMuted)
  }

  return (
    <div className="theo-player">
      {collections && (
        <div>
          <VideoPlayer
            ref={playerRef}
            isFullWindow={isFullWindow}
            onExitFullWindow={handleExitFullWindow}
            poster={collections?.FeaturedImage?.[0]?.URL}
            sources={[
              {
                src: collections?.FeaturedVideo?.[0]?.URL,
                type: "video/mp4"
              }
            ]}
          />
          <div className="player-top-layer" />
          <div className="player-content-layer">
            <h2>{collections?.Name}</h2>
            <div className="player-action bx--grid bx--grid--narrow">
              <div className="bx--row">
                <div className="bx--col-lg-3 bx--col-md-2 bx--col-sm-4">
                  <BuyAccess price={price} />
                </div>

                <div className="bx--col-lg-7 bx--col-md-5 bx--col-sm-4">
                  <p>{`Learn and get insights about architecture and interior design from SeloJene, located in the small town Salatiga, Indonesia, the residence of Ary Indra, the founder of Aboday, and the head curator of the Indonesian Pavilion at Venice Architectur Biennale 2018.`}</p>
                </div>

                <div className="bx--col-lg-1 bx--col-md-1 bx--col-sm-0">
                  <div className="player-icons">
                    <Button
                      hasIconOnly
                      renderIcon={isMuted ? IconMute : IconUnmute}
                      kind="ghost"
                      tooltipAlignment="center"
                      tooltipPosition="bottom"
                      onClick={handleToogleMuted}
                      iconDescription={isMuted ? "Unmute sound" : "Mute sound"}
                    />
                    <Button
                      hasIconOnly
                      renderIcon={IconMaximize}
                      kind="ghost"
                      tooltipAlignment="center"
                      tooltipPosition="bottom"
                      onClick={handleFullScreen}
                      iconDescription="Fullscreen"
                    />
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}
