import useSWR from "swr"
import { fetcherWithToken } from "../Api"
import { useToken } from "./useToken"

var headers = new Headers()
headers.append("Content-Type", "application/json")

var body = JSON.stringify({
  PlanCode: "b068ed20-3d95-11eb-ba40-85ca963ad9b0",
  Type: "PaidContent",
  PaymentMethod: "Midtrans"
})

var requestOptions = {
  method: "POST",
  headers,
  body
}

export function usePayment() {
  const { token } = useToken()
  const { data: payment } = useSWR(
    () => token && `payments/midtrans/checkout_contents?access_token=${token}`,
    {
      fetcher: (param) => fetcherWithToken(param, requestOptions)
    }
  )
  return payment?.data
}
